1	export type Customer = { yearsWithMHPCO: number };
2	export type Item = {
3	  type: string;
4	  material?: string;
5	  enchantment?: number;
6	  cursed?: boolean;
7	};
8	export type Damage = { itemType: string; amount: number };
9	export type Incident = { cause: string; damages: Damage[] };
10	export type QuoteStep = { op: "quote"; items: Item[] };
11	export type ClaimStep = { op: "claim"; policy: number; incident: Incident };
12	export type Step = QuoteStep | ClaimStep;
13	export type Scenario = { customer: Customer; steps: Step[] };
14	export type QuoteResult = { premium: number };
15	export type ClaimResult = { payout: number; remainingCap: number };
16	export type ScenarioResult = { results: (QuoteResult | ClaimResult)[] };
17	
18	const PROCESSING_FEE = 5;
19	const FIRST_INSURANCE_RATE = 0.1;
20	
21	const BASE_PREMIUMS: Record<string, number> = {
22	  sword: 100,
23	  amulet: 60,
24	  staff: 80,
25	  potion: 40,
26	  rune: 25,
27	};
28	
29	const baseFor = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
30	
31	const BLOCK_OF_3_PREMIUM = 60;
32	
33	const sumBasePremiums = (items: Item[]): number => {
34	  const runes = items.filter((i) => i.type === "rune").length;
35	  const others = items.filter((i) => i.type !== "rune");
36	  const runesBase = runes === 3 ? BLOCK_OF_3_PREMIUM : runes * baseFor({ type: "rune" });
37	  return runesBase + others.reduce((sum, item) => sum + baseFor(item), 0);
38	};
39	
40	const quotePremium = (items: Item[]): number => {
41	  const itemsBase = sumBasePremiums(items);
42	  const firstInsurance = itemsBase * FIRST_INSURANCE_RATE;
43	  return Math.ceil(itemsBase + firstInsurance + PROCESSING_FEE);
44	};
45	
46	export const runScenario = (scenario: Scenario): ScenarioResult => {
47	  const results = scenario.steps.map((step) => {
48	    if (step.op === "quote") return { premium: quotePremium(step.items) };
49	    return { payout: 0, remainingCap: 0 };
50	  });
51	  return { results };
52	};
